mapper.update:
UPDATE SUPPLIES
SET STOCK_QTY = STOCK_QTY - #{ea}
WHERE SUPPLY_SEQ = #{supply_seq}
AND STOCK_QTY >= #{ea}

UPDATE SUPPLY_RENTAL
SET RETURN_DATE = SYSDATE
